mapper.select:
SELECT *
FROM stock_move


        AND id = #{query.id}


        AND picking_id = #{query.pickingId}


        AND production_id = #{query.productionId}


        AND product_id = #{query.productId}


        AND origin_ref = #{query.originRef}


        AND source_line_ref = #{query.sourceLineRef}


        AND move_role = #{query.moveRole}


        AND (
            name ILIKE CONCAT('%', #{query.keyword}, '%')
            OR origin_ref ILIKE CONCAT('%', #{query.keyword}, '%')
            OR source_line_ref ILIKE CONCAT('%', #{query.keyword}, '%')
        )


        AND state = #{query.state}


ORDER BY id DESC
